mapper.update:
MERGE
    INTO BUDGET_MASTER M
        USING DUAL
        ON (
            M.DEPT_CD = #{deptCd}
                AND M.BGT_YR = #{bgtYr}
            )
        WHEN MATCHED THEN
            UPDATE
                SET M.BGT_TOT_AMT = M.BGT_TOT_AMT + #{bgtTotAmt}
        WHEN NOT MATCHED THEN
            INSERT
                (
                 BGT_M_CD
                , DEPT_CD
                , BGT_YR
                , BGT_TOT_AMT
                , BGT_STTS
                , BGT_REG_DT
                )
                VALUES
                    (
                      SEQ_BGT_M_CD.NEXTVAL
                    , #{deptCd}
                    , #{bgtYr}
                    , #{bgtTotAmt}
                    , '정상'
                    , SYSDATE
                    )

mapper.insert:
INSERT
INTO BUDGET_LOG
(
  LOG_NO
, BGT_M_CD
, BGT_CD
, BGT_CHG_SE
, BGT_CHG_AMT
, BGT_CHG_RSN
, APRV_NO
, EMP_ID
, BGT_CHG_DT
)
VALUES
    (
      SEQ_BUDGET_LOG_NO.NEXTVAL
    , #{bgtMCd}
    , NULL
    , #{bgtChgSe}
    , #{bgtTotAmt}
    , #{bgtChgRsn}
    , #{aprvNo}
    , #{empId}
    , SYSDATE
    )

